import 'dart:async';
import 'package:flutter/material.dart';

// A widget that subscribes to a Stream — showcasing the full lifecycle.
class TickerCounter extends StatefulWidget {
  const TickerCounter({super.key, required this.stream});
  final Stream<int> stream;

  @override
  State<TickerCounter> createState() => _TickerCounterState();
}

class _TickerCounterState extends State<TickerCounter> {
  StreamSubscription<int>? _sub;
  int _value = 0;

  @override
  void initState() {
    super.initState();
    debugPrint('initState');
    _sub = widget.stream.listen(_onTick);   // subscribe ONCE
  }

  @override
  void didChangeDependencies() {
    super.didChangeDependencies();
    debugPrint('didChangeDependencies (theme/media changed)');
  }

  @override
  void didUpdateWidget(TickerCounter oldWidget) {
    super.didUpdateWidget(oldWidget);
    if (oldWidget.stream != widget.stream) {
      // Parent gave us a DIFFERENT stream — resubscribe.
      _sub?.cancel();
      _sub = widget.stream.listen(_onTick);
    }
  }

  void _onTick(int v) {
    if (!mounted) return;                    // don't setState after dispose
    setState(() => _value = v);
  }

  @override
  void dispose() {
    debugPrint('dispose');
    _sub?.cancel();                          // release the subscription
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    debugPrint('build');
    return Center(child: Text('tick = $_value', style: Theme.of(context).textTheme.headlineMedium));
  }
}

// This covers every important pattern:
//   1. One-time subscribe in initState
//   2. Re-subscribe in didUpdateWidget if the input stream changed
//   3. Guard setState with `mounted`
//   4. Cancel subscription in dispose
//   5. Read Theme in build (or didChangeDependencies) — NOT initState

